// Validação do segredo do webhook
const secret = $env.WHATSAPP_WEBHOOK_SECRET;
const receivedSecret = $input.item.json.headers?.['x-webhook-secret'] 
  || $input.item.json.headers?.['x-hub-signature-256']
  || $input.item.json.query?.secret;

if (secret && receivedSecret !== secret) {
  throw new Error('Webhook secret inválido');
}

return { valid: true, payload: $input.item.json.body };

// Normaliza o payload do provedor para o modelo interno
const body = $input.item.json.payload;
const correlationId = 'msg-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);

// Suporte ao formato Evolution API
let normalized = null;

if (body?.data?.message) {
  const msg = body.data.message;
  const key = msg.key || {};
  const pushName = body.data?.pushName || body.data?.verifiedBizName || '';

  normalized = {
    messageId: key.id || '',
    instanceId: body.instance || '',
    fromNumber: key.remoteJid?.replace('@s.whatsapp.net', '').replace('@g.us', '') || '',
    toNumber: body.sender || '',
    contactName: pushName,
    text: msg.message?.conversation 
      || msg.message?.extendedTextMessage?.text 
      || msg.message?.imageMessage?.caption
      || msg.message?.videoMessage?.caption
      || '',
    messageType: (() => {
      if (msg.message?.conversation || msg.message?.extendedTextMessage) return 'Text';
      if (msg.message?.imageMessage) return 'Image';
      if (msg.message?.audioMessage || msg.message?.pttMessage) return 'Audio';
      if (msg.message?.videoMessage) return 'Video';
      if (msg.message?.documentMessage) return 'Document';
      if (msg.message?.stickerMessage) return 'Sticker';
      if (msg.message?.locationMessage) return 'Location';
      return 'Unknown';
    })(),
    timestamp: new Date(msg.messageTimestamp ? msg.messageTimestamp * 1000 : Date.now()).toISOString(),
    mediaUrl: msg.message?.imageMessage?.url 
      || msg.message?.audioMessage?.url 
      || msg.message?.videoMessage?.url
      || msg.message?.documentMessage?.url
      || null,
    quotedMessageId: msg.message?.extendedTextMessage?.contextInfo?.stanzaId || null,
    status: 'Received',
    providerMetadata: JSON.stringify({ event: body.event, instance: body.instance }),
    correlationId,
    isFromMe: key.fromMe || false,
    isGroup: key.remoteJid?.includes('@g.us') || false
  };
}

if (!normalized) {
  throw new Error('Formato de payload não reconhecido: ' + JSON.stringify(body).substring(0, 200));
}

return { normalized, correlationId };

// Registra o erro e retorna resposta de falha
const error = $input.item.json.error || 'Erro desconhecido';
console.error('[Webhook] Erro:', error, 'Correlation:', $json?.correlationId);
return { error: error, correlationId: $json?.correlationId || 'unknown' };
